/* contact us form - for shortcode block */

/* Main container - WIDER */
.contact-us-form {
    max-width: 1200px;
    margin: 50px auto;
    position: relative;
    width: 100%;
}

/* Form background - RED image with FULL OPACITY */
.contact-us-form form,
.contact-us-form .wpcf7-form {
    /* Red background - full opacity, no overlay */
    background: url('https://i.imgur.com/2HWAQ4a.png') !important;
    background-repeat: no-repeat !important;
    background-position: center !important;
    background-size: cover !important;
    
    padding: 60px 80px 30px 80px; /* Reduced bottom padding from 60px to 30px */
    border-radius: 24px;
    box-shadow: 0 20px 40px rgba(0, 0, 0, 0.12);
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    width: 100%;
    box-sizing: border-box;
}

/* Make form fields display in columns for wider layout */
.contact-us-form .wpcf7-form {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 30px;
    margin-bottom: 0; /* Ensure no extra margin */
}

/* Name field - spans full width or first column */
.contact-us-form .wpcf7-form p:has([name="your-name"]) {
    grid-column: span 1;
    margin: 0;
}

/* Email field - second column */
.contact-us-form .wpcf7-form p:has([name="your-email"]) {
    grid-column: span 1;
    margin: 0;
}

/* Subject field - full width */
.contact-us-form .wpcf7-form p:has([name="your-subject"]) {
    grid-column: span 2;
    margin: 0;
}

/* Message field - full width */
.contact-us-form .wpcf7-form p:has([name="your-message"]) {
    grid-column: span 2;
    margin: 0;
}

/* File upload - full width - THINNER */
.contact-us-form .wpcf7-form p:has([type="file"]) {
    grid-column: span 2;
    margin: 0;
}

/* Submit button - full width */
.contact-us-form .wpcf7-form p:has([type="submit"]) {
    grid-column: span 2;
    margin: 0 0 5px 0; /* Reduced bottom margin */
}

/* Akismet privacy text - full width - FORCE SINGLE LINE */
.contact-us-form .wpcf7-form p:last-child {
    grid-column: span 2;
    margin: 0 0 0 0 !important; /* Removed all margins */
    padding: 5px 0 0 0; /* Minimal top padding only */
    border-top: 1px solid rgba(255, 255, 255, 0.2);
    color: #ffffff !important;
    font-size: 13px;
    text-align: left;
    text-shadow: 0 1px 2px rgba(0, 0, 0, 0.2);
    
    /* Force single line */
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis; /* Adds ... if it still overflows */
    width: 100%;
    display: block;
}

/* The link itself - keep inline */
.contact-us-form form p:last-child a,
.contact-us-form .wpcf7-form p:last-child a {
    color: #3b82f6 !important;
    text-decoration: underline;
    font-weight: 500;
    white-space: nowrap;
    display: inline;
    margin-left: 3px;
}

/* Form labels - WHITE on red background */
.contact-us-form label {
    display: block;
    margin-bottom: 8px; /* Slightly reduced */
    color: #ffffff !important;
    font-weight: 600;
    font-size: 15px;
    letter-spacing: 0.3px;
    text-shadow: 0 2px 4px rgba(0, 0, 0, 0.2);
}

/* DIRECT LABEL TEXT REPLACEMENT */
/* First label - "Your name" → "Name" */
.contact-us-form label:has([name="your-name"]) {
    color: transparent !important;
    position: relative;
    display: block;
}
.contact-us-form label:has([name="your-name"])::before {
    content: "Name";
    position: absolute;
    left: 0;
    top: 0;
    color: #ffffff;
    font-weight: 600;
    font-size: 15px;
    letter-spacing: 0.3px;
    text-shadow: 0 2px 4px rgba(0, 0, 0, 0.2);
}

/* Second label - "Your email" → "Email" */
.contact-us-form label:has([name="your-email"]) {
    color: transparent !important;
    position: relative;
    display: block;
}
.contact-us-form label:has([name="your-email"])::before {
    content: "Email";
    position: absolute;
    left: 0;
    top: 0;
    color: #ffffff;
    font-weight: 600;
    font-size: 15px;
    letter-spacing: 0.3px;
    text-shadow: 0 2px 4px rgba(0, 0, 0, 0.2);
}

/* Third label - "Subject" - keep as is */

/* Fourth label - "Your message (optional)" → "Message (optional)" */
.contact-us-form label:has([name="your-message"]) {
    color: transparent !important;
    position: relative;
    display: block;
}
.contact-us-form label:has([name="your-message"])::before {
    content: "Message (optional)";
    position: absolute;
    left: 0;
    top: 0;
    color: #ffffff;
    font-weight: 600;
    font-size: 15px;
    letter-spacing: 0.3px;
    text-shadow: 0 2px 4px rgba(0, 0, 0, 0.2);
}

/* Fifth label - file upload - keep as is */

/* Input fields - YELLOW background pattern */
.contact-us-form input[type="text"],
.contact-us-form input[type="email"],
.contact-us-form input[type="tel"],
.contact-us-form textarea {
    width: 100% !important;
    padding: 16px 20px !important;
    margin-bottom: 0 !important;
    border: 1.5px solid rgba(255, 255, 255, 0.3);
    border-radius: 12px;
    font-size: 16px;
    transition: all 0.2s ease;
    box-sizing: border-box;
    display: block !important;
    
    /* Yellow background pattern - tiled */
    background: url('https://i.imgur.com/oNsj5wK.png') !important;
    background-repeat: repeat !important;
    background-position: 0 0 !important;
    background-size: auto !important;
    color: #1e293b;
}

/* File input - THINNER */
.contact-us-form input[type="file"] {
    width: 100% !important;
    padding: 15px 20px !important; /* Slightly reduced from 20px */
    margin-bottom: 0 !important;
    border: 2px dashed rgba(255, 255, 255, 0.5);
    border-radius: 12px;
    font-size: 15px;
    transition: all 0.2s ease;
    box-sizing: border-box;
    display: block !important;
    cursor: pointer;
    
    /* Yellow background pattern */
    background: url('https://i.imgur.com/oNsj5wK.png') !important;
    background-repeat: repeat !important;
    background-position: 0 0 !important;
    background-size: auto !important;
    color: #1e293b;
    backdrop-filter: blur(5px);
    text-align: left;
    line-height: 1.2;
}

/* File input label - adjust spacing */
.contact-us-form label:has(+ input[type="file"]) {
    margin-bottom: 5px;
}

/* File input hover effect */
.contact-us-form input[type="file"]:hover {
    border-color: #ffffff;
    filter: brightness(1.05);
}

/* Placeholder text color */
.contact-us-form input::placeholder,
.contact-us-form textarea::placeholder {
    color: #334155;
    opacity: 0.8;
}

/* Focus states */
.contact-us-form input[type="text"]:focus,
.contact-us-form input[type="email"]:focus,
.contact-us-form input[type="tel"]:focus,
.contact-us-form textarea:focus,
.contact-us-form input[type="file"]:focus {
    border-color: #3b82f6 !important;
    background: url('https://i.imgur.com/oNsj5wK.png') !important;
    background-repeat: repeat !important;
    background-position: 0 0 !important;
    background-size: auto !important;
    box-shadow: 0 0 0 4px rgba(59, 130, 246, 0.3);
    outline: none;
}

/* Submit button */
.contact-us-form input[type="submit"] {
    background: rgba(59, 130, 246, 0.9);
    color: white;
    padding: 16px 32px; /* Slightly reduced padding */
    border: none;
    border-radius: 12px;
    font-size: 18px;
    font-weight: 600;
    cursor: pointer;
    transition: all 0.2s ease;
    width: 100%;
    letter-spacing: 0.5px;
    margin: 0; /* Removed margin */
    backdrop-filter: blur(5px);
    border: 1px solid rgba(255, 255, 255, 0.2);
}

.contact-us-form input[type="submit"]:hover {
    background: #2563eb;
    transform: translateY(-2px);
    box-shadow: 0 8px 20px rgba(0, 0, 0, 0.3);
}

/* Validation messages */
.contact-us-form .wpcf7-not-valid-tip {
    color: #ffb4b4;
    font-size: 13px;
    margin-top: 5px;
    margin-bottom: 0;
    display: block;
    text-shadow: 0 1px 2px rgba(0, 0, 0, 0.3);
}

/* Success message */
.contact-us-form .wpcf7-mail-sent-ok {
    background: rgba(16, 185, 129, 0.9);
    color: white;
    padding: 12px 20px; /* Reduced padding */
    border-radius: 12px;
    margin: 10px 0 0 0; /* Reduced margin */
    border: 1px solid rgba(255, 255, 255, 0.2);
    font-size: 16px;
    text-align: center;
    font-weight: 500;
    backdrop-filter: blur(5px);
    grid-column: span 2;
}

/* Response area */
.contact-us-form .wpcf7-response-output {
    margin: 10px 0 0 0 !important; /* Reduced margin */
    padding: 10px !important; /* Reduced padding */
    border-radius: 12px;
    border: none !important;
    font-size: 15px;
    grid-column: span 2;
}

/* Hide line breaks */
.contact-us-form br {
    display: none;
}

/* Mobile */
@media (max-width: 768px) {
    .contact-us-form {
        max-width: 95%;
        margin: 30px auto;
    }
    
    .contact-us-form .wpcf7-form {
        grid-template-columns: 1fr;
        gap: 20px;
    }
    
    .contact-us-form .wpcf7-form p {
        grid-column: span 1 !important;
    }
    
    .contact-us-form form,
    .contact-us-form .wpcf7-form {
        padding: 30px 20px 20px 20px; /* Reduced bottom padding */
    }
    
    .contact-us-form input[type="text"],
    .contact-us-form input[type="email"],
    .contact-us-form input[type="tel"],
    .contact-us-form textarea {
        padding: 14px 15px !important;
    }
    
    /* File input - thinner on mobile too */
    .contact-us-form input[type="file"] {
        padding: 12px 15px !important;
        font-size: 14px;
    }
    
    .contact-us-form input[type="submit"] {
        padding: 14px 28px;
        font-size: 17px;
    }
    
    /* Allow wrapping on mobile since screen is small */
    .contact-us-form .wpcf7-form p:last-child {
        white-space: normal;
        text-align: center;
        font-size: 12px;
    }
}

/* Large screens */
@media (min-width: 1200px) {
    .contact-us-form {
        max-width: 1400px;
    }
    
    .contact-us-form form,
    .contact-us-form .wpcf7-form {
        padding: 70px 100px 30px 100px; /* Reduced bottom padding */
    }
    
    /* Keep file input thin on large screens */
    .contact-us-form input[type="file"] {
        padding: 18px 20px !important;
    }
}



















































