.rt-two-clum {
  display: flex;
  gap: 60px; /* Space between columns */
  justify-content: space-between;
  max-width: 1200px; /* Slightly narrower for two columns */
  margin: 0 auto;
  padding: 20px;
}

.rt-two-clum .column {
  flex: 1; /* Equal width columns */
  text-align: center;
}

.rt-two-clum .column img {
  width: 100%;
  max-width: 700px; /* Even bigger images since there's only two */
  height: 500px; /* Taller images */
  object-fit: cover; /* Prevents distortion */
  border-radius: 8px; /* Optional: rounded corners */
}







.rt-paragraph-block {
  /* Your existing paragraph styles */
}

.rt-paragraph-block a {
  text-decoration: underline;
  text-decoration-color: #FEA240; /* Underline color always #FEA240 */
  color: currentColor; /* Keeps text color as default */
  transition: color 0.3s ease, text-decoration-color 0.3s ease; /* Smooth transition for both */
  position: relative; /* For pseudo-element positioning */
  outline: none !important; /* Removes the white outline */
  -webkit-tap-highlight-color: transparent; /* Removes mobile tap highlight */
}

.rt-paragraph-block a:focus {
  outline: none !important; /* Removes focus outline */
}

.rt-paragraph-block a:active {
  outline: none !important; /* Removes active state outline */
}

.rt-paragraph-block a:hover {
  color: #FEA240; /* Changes text color on hover */
  text-decoration-color: #F24131; /* Changes underline color on hover to red */
}

.rt-paragraph-block a:hover::after {
  content: ">";
  display: inline;
  color: #F24131; /* Changed from #FEA240 to #F24131 */
}










