    padding: 24px 48px !important;
    border-radius: 8px !important;
    margin-left: 100px !important;   /* space from image */
    margin-right: 300px !important;  /* space from right wall */
    box-sizing: border-box !important;
}























.block-cover {
    display: flex !important;
    align-items: flex-start !important; /* This moves content to the top */
    justify-content: flex-start !important; /* This moves content to the left if needed */
}

/* Background image for detail blocks */
.detail-blocks {
   background-image: url('https://i.imgur.com/QSfcX04.png');
   background-size: cover;
   background-position: center;
   background-repeat: no-repeat;
}








/* Target all details blocks */
.wp-block-details {
    margin-left: auto !important;
    margin-right: auto !important;
    width: 100% !important;
}

.wp-block-details summary {
    list-style: none !important;
    cursor: pointer !important;
    padding: 15px 20px !important;
    transition: color 0.3s ease !important;
    outline: none !important;
    box-shadow: none !important;
    -webkit-tap-highlight-color: transparent !important;
    display: flex !important;
    align-items: center !important;
    gap: 8px !important; /* Space between text and arrow */
}

/* Remove focus outline when clicked */
.wp-block-details summary:focus,
.wp-block-details summary:active,
.wp-block-details summary:focus-visible {
    outline: none !important;
    box-shadow: none !important;
}

/* Hover effect - text color changes */
.wp-block-details summary:hover {
    color: #F24131 !important;
}

/* >> symbol right next to the text (default state) */
.wp-block-details summary::after {
    content: ">>" !important;
    color: inherit !important;
    transition: color 0.3s ease !important;
    font-size: inherit !important;
}

/* When open, show >>> (in red) */
.wp-block-details[open] summary::after {
    content: ">>>" !important; /* Changed from >> to >>> */
}

/* Hover effect - changes to >>> on hover */
.wp-block-details summary:hover::after {
    content: ">>>" !important;
    color: inherit !important;
    margin-left: 4px !important;
    display: inline !important;
    font-size: inherit !important;
}

/* When details is open - title and arrow turn red */
.wp-block-details[open] summary,
.wp-block-details[open] summary::after {
    color: #F24131 !important;
}

/* Remove default triangle */
.wp-block-details summary::-webkit-details-marker {
    display: none !important;
}

.wrap-fix{
white-space: nowrap;

}




/* Container for media text with image on LEFT, text on RIGHT */
.n-media-text-right {
    max-width: 100% !important;
}

/* Image on the LEFT */
.n-media-text-right .wp-block-media-text__media img {
    width: 70% !important;
    height: auto !important;
    object-fit: cover !important;
    display: block !important;
    margin-right: auto !important;   /* anchor image to left */
    margin-left: 300px !important;   /* space from left wall */
}

/* Text on the RIGHT with box design */
.n-media-text-right .wp-block-media-text__content {
    background-color: #F7F4EB !important;
    padding: 24px 48px !important;
    border-radius: 8px !important;
    margin-left: 100px !important;   /* space from image */
    margin-right: 300px !important;  /* space from right wall */
    box-sizing: border-box !important;
}





.rt-three-clum {
  display: flex !important;
  gap: 60px !important;
  justify-content: space-between !important;
  max-width: 1600px !important;
  margin: 0 auto !important;
  padding: 20px !important;
}

.rt-three-clum .column {
  flex: 1 !important;
}

/* Target lists inside cover block */
.wp-block-cover .rt-three-clum .column li,
.wp-block-cover .rt-three-clum .column ul,
.wp-block-cover .rt-three-clum .column ol {
  white-space: nowrap !important;
}

/* Even more specific */
body .wp-block-cover .rt-three-clum .column * {
  white-space: nowrap !important;
}














/* Target buttons inside a Buttons block to match your style */
.wp-block-buttons .wp-block-button__link {
    background: #f3bd48 !important;
    color: #000000 !important;
    border: 2px solid #f3bd48 !important;
    border-radius: 0 !important;
    padding: 24px 45px !important;
    font-size: 32px !important;
    line-height: 36px !important;
    letter-spacing: 3.2px !important;
    text-transform: uppercase !important;
    transition: 0.25s ease-in-out !important;
    margin-bottom: 20px !important;
    display: inline-block !important;
    text-decoration: none !important;
}

/* Hover effect - white text on hover */
.wp-block-buttons .wp-block-button__link:hover {
    background: #882346 !important;
    border-color: #882346 !important;
    color: #ffffff !important; /* Changed from #000000 to #ffffff */
}






/* Container for all three columns - full width */
.three-columns {
    display: grid;
    grid-template-columns: repeat(3, 1fr); /* 3 equal columns */
    width: 100vw !important;
    max-width: 100vw !important;
    margin-left: calc(-50vw + 50%) !important;
    margin-right: calc(-50vw + 50%) !important;
     gap: 20px !important; /* Space BETWEEN columns */
    padding-top: 15px !important; /* Space at the LEFT and RIGHT edges of the container */
    padding-right: 300px !important; /* Space at the LEFT and RIGHT edges of the container */
    padding-left: 300px !important; /* Space at the LEFT and RIGHT edges of the container */
}



/* Add padding to create space from edges */
.three-columns > * {
    background-color: #F7F4EB !important;
    padding: 40px 30px !important; /* Adds space INSIDE each column */
    margin: 20px !important; /* Adds space OUTSIDE each column (between columns and edges) */
    border-radius: 8px; /* Optional: adds slight rounded corners */
}










/* Container for two columns - matching three-columns style */
.two-columns {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    width: 100vw !important;
    max-width: 100vw !important;
    margin-left: calc(-50vw + 50%) !important;
    margin-right: calc(-50vw + 50%) !important;
    gap: 50px !important; /* INCREASED from 30px */
    padding: 15px 580px !important; /* INCREASED from 450px */
    box-sizing: border-box !important;
}

/* Style for each column - matching three-columns inner style */
.two-columns > * {
    background-color: #F7F4EB !important;
    padding: 30px 25px !important; /* Slightly adjusted */
    margin: 30px !important; /* INCREASED from 25px */
    border-radius: 8px;
    box-sizing: border-box !important;
}

